jayess_value *jayess_glfw_get_proc_address(jayess_value *name_value) {
    const char *name = jayess_expect_string(name_value, "jayess_glfw_get_proc_address");
    GLFWglproc proc = NULL;
    char text[32];
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    proc = glfwGetProcAddress(name);
    if (proc == NULL) {
        return jayess_value_undefined();
    }
    snprintf(text, sizeof(text), "%" PRIuPTR, (uintptr_t) proc);
    return jayess_value_from_bigint(text);
}

