jayess_value *jayess_glfw_get_required_vulkan_instance_extensions(void) {
    uint32_t count = 0;
    const char **extensions = glfwGetRequiredInstanceExtensions(&count);
    jayess_array *values = jayess_array_new();
    uint32_t i = 0;
    if (extensions == NULL) {
        return jayess_value_undefined();
    }
    for (i = 0; i < count; i++) {
        jayess_array_push_value(values, jayess_value_from_string(extensions[i]));
    }
    return jayess_value_from_array(values);
}

jayess_value *jayess_glfw_get_vulkan_instance_proc_address(jayess_value *name_value) {
    const char *name = jayess_expect_string(name_value, "jayess_glfw_get_vulkan_instance_proc_address");
    char text[32];
    GLFWvkproc proc = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
#if defined(VK_VERSION_1_0)
    proc = glfwGetInstanceProcAddress(VK_NULL_HANDLE, name);
#else
    (void) name;
#endif
    if (proc == NULL) {
        return jayess_value_undefined();
    }
    snprintf(text, sizeof(text), "%" PRIuPTR, (uintptr_t) proc);
    return jayess_value_from_bigint(text);
}

jayess_value *jayess_glfw_create_vulkan_surface(jayess_value *window_value, jayess_value *instance_value) {
    GLFWwindow *window = (GLFWwindow *) jayess_expect_native_handle(window_value, "GLFWwindow", "jayess_glfw_create_vulkan_surface");
    uintptr_t raw_instance = 0;
    char text[32];
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
#if defined(VK_VERSION_1_0)
    VkSurfaceKHR surface = VK_NULL_HANDLE;
    VkResult result = VK_ERROR_INITIALIZATION_FAILED;
    if (!jayess_glfw_parse_pointer_value(instance_value, "jayess_glfw_create_vulkan_surface", &raw_instance)) {
        return jayess_value_undefined();
    }
    if (raw_instance == 0) {
        jayess_throw_type_error("jayess_glfw_create_vulkan_surface expected non-zero Vulkan instance handle");
        return jayess_value_undefined();
    }
    result = glfwCreateWindowSurface((VkInstance) raw_instance, window, NULL, &surface);
    if (result != VK_SUCCESS) {
        char message[160];
        snprintf(message, sizeof(message), "glfwCreateWindowSurface failed with VkResult %d", (int) result);
        jayess_throw_error(message);
        return jayess_value_undefined();
    }
    snprintf(text, sizeof(text), "%" PRIuPTR, (uintptr_t) surface);
    return jayess_value_from_bigint(text);
#else
    void *surface = NULL;
    int result = -1;
    if (!jayess_glfw_parse_pointer_value(instance_value, "jayess_glfw_create_vulkan_surface", &raw_instance)) {
        return jayess_value_undefined();
    }
    if (raw_instance == 0) {
        jayess_throw_type_error("jayess_glfw_create_vulkan_surface expected non-zero Vulkan instance handle");
        return jayess_value_undefined();
    }
    result = glfwCreateWindowSurface((void *) raw_instance, window, NULL, &surface);
    if (result != 0) {
        char message[160];
        snprintf(message, sizeof(message), "glfwCreateWindowSurface failed with VkResult %d", result);
        jayess_throw_error(message);
        return jayess_value_undefined();
    }
    snprintf(text, sizeof(text), "%" PRIuPTR, (uintptr_t) surface);
    return jayess_value_from_bigint(text);
#endif
}

