jayess_value *jayess_glfw_set_key_callback(jayess_value *window_value, jayess_value *callback_value) {
    GLFWwindow *window = (GLFWwindow *) jayess_expect_native_handle(window_value, "GLFWwindow", "jayess_glfw_set_key_callback");
    jayess_glfw_callback_state *state = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (!jayess_glfw_require_callback(callback_value)) {
        return jayess_value_undefined();
    }
    state = jayess_glfw_callback_state_from_window(window);
    if (state == NULL) {
        jayess_throw_error("missing glfw callback state");
        return jayess_value_undefined();
    }
    state->key_callback = callback_value;
    glfwSetKeyCallback(window, jayess_glfw_key_callback);
    return jayess_value_undefined();
}

